import api from './api';

// Mock data for fallback
const mockPatients = [
  {
    id: 'PAT001',
    name: 'John Doe',
    email: 'john.doe@example.com',
    password: 'patient123',
    phone: '+1 234-567-8901',
    bloodGroup: 'O+',
    emergencyContact: 'Jane Doe: +1 234-567-8902',
    address: '123 Main St, NY',
    role: 'patient'
  }
];

// Patient Login
export const patientLogin = async (email, password) => {
  try {
    const response = await api.post('/patients/login', { email, password });
    if (response.data.success) {
      localStorage.setItem('token', response.data.token);
      localStorage.setItem('patientUser', JSON.stringify(response.data.user));
      return response.data.user;
    }
  } catch (error) {
    // Fallback to mock data
    const patient = mockPatients.find(p => p.email === email && p.password === password);
    if (patient) {
      const { password, ...patientWithoutPassword } = patient;
      localStorage.setItem('patientUser', JSON.stringify(patientWithoutPassword));
      return patientWithoutPassword;
    }
    throw new Error('Invalid credentials');
  }
};

// Patient Signup
export const patientSignup = async (patientData) => {
  try {
    const response = await api.post('/patients/register', patientData);
    if (response.data.success) {
      localStorage.setItem('token', response.data.token);
      localStorage.setItem('patientUser', JSON.stringify(response.data.user));
      return response.data.user;
    }
  } catch (error) {
    // Mock signup
    const newPatient = {
      id: `PAT${String(mockPatients.length + 1).padStart(3, '0')}`,
      ...patientData,
      role: 'patient'
    };
    localStorage.setItem('patientUser', JSON.stringify(newPatient));
    return newPatient;
  }
};

// Patient Logout
export const patientLogout = () => {
  localStorage.removeItem('token');
  localStorage.removeItem('patientUser');
};

// Get stored patient (for PrivateRoute)
export const getStoredPatient = () => {
  const user = localStorage.getItem('patientUser');
  return user ? JSON.parse(user) : null;
};

// ⚠️ IMPORTANT: Add this function - it's what your components are importing!
export const getCurrentPatient = () => {
  return getStoredPatient();
};
